// Set uses given function f to mock the VideoAsset.Select method
func (mmSelect *mVideoAssetMockSelect) Set(f func(ctx context.Context, videoID uuid.UUID) (va1 []domain.VideoAsset, err error)) *VideoAssetMock {
	if mmSelect.defaultExpectation != nil {
		mmSelect.mock.t.Fatalf("Default expectation is already set for the VideoAsset.Select method")
	}

	if len(mmSelect.expectations) > 0 {
		mmSelect.mock.t.Fatalf("Some expectations are already set for the VideoAsset.Select method")
	}

	mmSelect.mock.funcSelect = f
	mmSelect.mock.funcSelectOrigin = minimock.CallerInfo(1)
	return mmSelect.mock
}

// When sets expectation for the VideoAsset.Select which will trigger the result defined by the following
// Then helper
func (mmSelect *mVideoAssetMockSelect) When(ctx context.Context, videoID uuid.UUID) *VideoAssetMockSelectExpectation {
	if mmSelect.mock.funcSelect != nil {
		mmSelect.mock.t.Fatalf("VideoAssetMock.Select mock is already set by Set")
	}

	expectation := &VideoAssetMockSelectExpectation{
		mock:               mmSelect.mock,
		params:             &VideoAssetMockSelectParams{ctx, videoID},
		expectationOrigins: VideoAssetMockSelectExpectationOrigins{origin: minimock.CallerInfo(1)},
	}
	mmSelect.expectations = append(mmSelect.expectations, expectation)
	return expectation
}

// Then sets up VideoAsset.Select return parameters for the expectation previously defined by the When method
func (e *VideoAssetMockSelectExpectation) Then(va1 []domain.VideoAsset, err error) *VideoAssetMock {
	e.results = &VideoAssetMockSelectResults{va1, err}
	return e.mock
}

// Times sets number of times VideoAsset.Select should be invoked
func (mmSelect *mVideoAssetMockSelect) Times(n uint64) *mVideoAssetMockSelect {
	if n == 0 {
		mmSelect.mock.t.Fatalf("Times of VideoAssetMock.Select mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmSelect.expectedInvocations, n)
	mmSelect.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmSelect
}

func (mmSelect *mVideoAssetMockSelect) invocationsDone() bool {
	if len(mmSelect.expectations) == 0 && mmSelect.defaultExpectation == nil && mmSelect.mock.funcSelect == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmSelect.mock.afterSelectCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmSelect.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// Select implements mm_repository.VideoAsset
func (mmSelect *VideoAssetMock) Select(ctx context.Context, videoID uuid.UUID) (va1 []domain.VideoAsset, err error) {
	mm_atomic.AddUint64(&mmSelect.beforeSelectCounter, 1)
	defer mm_atomic.AddUint64(&mmSelect.afterSelectCounter, 1)

	mmSelect.t.Helper()

	if mmSelect.inspectFuncSelect != nil {
		mmSelect.inspectFuncSelect(ctx, videoID)
	}

	mm_params := VideoAssetMockSelectParams{ctx, videoID}

	// Record call args
	mmSelect.SelectMock.mutex.Lock()
	mmSelect.SelectMock.callArgs = append(mmSelect.SelectMock.callArgs, &mm_params)
	mmSelect.SelectMock.mutex.Unlock()

	for _, e := range mmSelect.SelectMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.va1, e.results.err
		}
	}

	if mmSelect.SelectMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmSelect.SelectMock.defaultExpectation.Counter, 1)
		mm_want := mmSelect.SelectMock.defaultExpectation.params
		mm_want_ptrs := mmSelect.SelectMock.defaultExpectation.paramPtrs

		mm_got := VideoAssetMockSelectParams{ctx, videoID}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.ctx != nil && !minimock.Equal(*mm_want_ptrs.ctx, mm_got.ctx) {
				mmSelect.t.Errorf("VideoAssetMock.Select got unexpected parameter ctx, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmSelect.SelectMock.defaultExpectation.expectationOrigins.originCtx, *mm_want_ptrs.ctx, mm_got.ctx, minimock.Diff(*mm_want_ptrs.ctx, mm_got.ctx))
			}

			if mm_want_ptrs.videoID != nil && !minimock.Equal(*mm_want_ptrs.videoID, mm_got.videoID) {
				mmSelect.t.Errorf("VideoAssetMock.Select got unexpected parameter videoID, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmSelect.SelectMock.defaultExpectation.expectationOrigins.originVideoID, *mm_want_ptrs.videoID, mm_got.videoID, minimock.Diff(*mm_want_ptrs.videoID, mm_got.videoID))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmSelect.t.Errorf("VideoAssetMock.Select got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmSelect.SelectMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmSelect.SelectMock.defaultExpectation.results
		if mm_results == nil {
			mmSelect.t.Fatal("No results are set for the VideoAssetMock.Select")
		}
		return (*mm_results).va1, (*mm_results).err
	}
	if mmSelect.funcSelect != nil {
		return mmSelect.funcSelect(ctx, videoID)
	}
	mmSelect.t.Fatalf("Unexpected call to VideoAssetMock.Select. %v %v", ctx, videoID)
	return
}

// SelectAfterCounter returns a count of finished VideoAssetMock.Select invocations
func (mmSelect *VideoAssetMock) SelectAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmSelect.afterSelectCounter)
}

// SelectBeforeCounter returns a count of VideoAssetMock.Select invocations
func (mmSelect *VideoAssetMock) SelectBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmSelect.beforeSelectCounter)
}

// Calls returns a list of arguments used in each call to VideoAssetMock.Select.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmSelect *mVideoAssetMockSelect) Calls() []*VideoAssetMockSelectParams {
	mmSelect.mutex.RLock()

	argCopy := make([]*VideoAssetMockSelectParams, len(mmSelect.callArgs))
	copy(argCopy, mmSelect.callArgs)

	mmSelect.mutex.RUnlock()

	return argCopy
}

// MinimockSelectDone returns true if the count of the Select invocations corresponds
// the number of defined expectations
func (m *VideoAssetMock) MinimockSelectDone() bool {
	if m.SelectMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.SelectMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.SelectMock.invocationsDone()
}

// MinimockSelectInspect logs each unmet expectation
func (m *VideoAssetMock) MinimockSelectInspect() {
	for _, e := range m.SelectMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to VideoAssetMock.Select at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterSelectCounter := mm_atomic.LoadUint64(&m.afterSelectCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.SelectMock.defaultExpectation != nil && afterSelectCounter < 1 {
		if m.SelectMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to VideoAssetMock.Select at\n%s", m.SelectMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to VideoAssetMock.Select at\n%s with params: %#v", m.SelectMock.defaultExpectation.expectationOrigins.origin, *m.SelectMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcSelect != nil && afterSelectCounter < 1 {
		m.t.Errorf("Expected call to VideoAssetMock.Select at\n%s", m.funcSelectOrigin)
	}

	if !m.SelectMock.invocationsDone() && afterSelectCounter > 0 {
		m.t.Errorf("Expected %d calls to VideoAssetMock.Select at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.SelectMock.expectedInvocations), m.SelectMock.expectedInvocationsOrigin, afterSelectCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *VideoAssetMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockCreateInspect()

			m.MinimockSelectInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *VideoAssetMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *VideoAssetMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockCreateDone() &&
		m.MinimockSelectDone()
}
